   292→                    <item.icon className="h-5 w-5" />
   293→                    {item.id === 'genitori' && hasNewInsights && (
   294→                      <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full animate-pulse" />
   295→                    )}
   296→                  </div>
   297→                )}
   298→                {sidebarOpen && <span className="font-medium">{item.label}</span>}
   299→              </button>
   300→            );
   301→          })}
   302→        </nav>
   303→
   304→        {/* XP Progress */}
   305→        {sidebarOpen && (
   306→          <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
   307→            <div className="mb-2 flex justify-between text-sm">
   308→              <span className="text-slate-600 dark:text-slate-400">XP</span>
   309→              <span className="font-medium text-slate-900 dark:text-white">
   310→                {xp.toLocaleString()}
