     1→// ============================================================================
     2→// CONVERGIO WEB - MAIN APPLICATION STORE (Zustand)
     3→// With database sync via API routes
     4→// ============================================================================
     5→
     6→import { create } from 'zustand';
     7→import { logger } from '@/lib/logger';
     8→import { onLevelUp, onStreakMilestone, onAchievement } from '@/lib/notifications/triggers';
     9→import type {
    10→  Maestro,
    11→  Theme,
    12→  AIProvider,
    13→  Streak,
    14→  Achievement,
    15→  SubjectMastery,
    16→  Conversation,
    17→  ChatMessage,
    18→  ToolCall,
    19→} from '@/types';
    20→
    21→// === SETTINGS STORE ===
    22→
    23→interface AppearanceSettings {
    24→  theme: 'light' | 'dark' | 'system';
    25→  accentColor: string;
    26→  language: 'it' | 'en' | 'es' | 'fr' | 'de';
    27→}
    28→
    29→// Teaching style from super encouraging to brutal
    30→export type TeachingStyle = 'super_encouraging' | 'encouraging' | 'balanced' | 'strict' | 'brutal';
    31→
    32→/**
    33→ * Learning differences that the platform supports.
    34→ * Used for buddy matching and accessibility features.
    35→ */
    36→export type LearningDifference =
    37→  | 'dyslexia'
    38→  | 'dyscalculia'
    39→  | 'dysgraphia'
    40→  | 'adhd'
    41→  | 'autism'
    42→  | 'cerebralPalsy'
    43→  | 'visualImpairment'
    44→  | 'auditoryProcessing';
    45→
    46→interface ExtendedStudentProfile {
    47→  name: string;
    48→  age: number;
    49→  schoolYear: number;
    50→  schoolLevel: 'elementare' | 'media' | 'superiore';
    51→  gradeLevel: string;
    52→  learningGoals: string[];
    53→  teachingStyle: TeachingStyle;
    54→  fontSize: 'small' | 'medium' | 'large' | 'extra-large';
    55→  highContrast: boolean;
    56→  dyslexiaFont: boolean;
    57→  voiceEnabled: boolean;
    58→  simplifiedLanguage: boolean;
    59→  adhdMode: boolean;
    60→  // MirrorBuddy character preferences
    61→  learningDifferences: LearningDifference[];
    62→  preferredCoach?: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
    63→  preferredBuddy?: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
    64→  // Custom border colors for coach and buddy avatars
    65→  coachBorderColor?: string;
    66→  buddyBorderColor?: string;
    67→}
    68→
    69→// Provider preference for manual selection
    70→export type ProviderPreference = 'azure' | 'ollama' | 'auto';
    71→
    72→interface SettingsState {
    73→  theme: Theme;
    74→  provider: AIProvider;
    75→  model: string;
    76→  budgetLimit: number;
    77→  totalSpent: number;
    78→  studentProfile: ExtendedStudentProfile;
    79→  appearance: AppearanceSettings;
    80→  preferredProvider: ProviderPreference;
    81→  preferredMicrophoneId: string; // Empty string = system default
    82→  preferredOutputId: string; // Empty string = system default (speakers)
    83→  preferredCameraId: string; // Empty string = system default
    84→  // Voice settings (Azure Realtime API)
    85→  voiceVadThreshold: number; // VAD sensitivity (0.3-0.7, default 0.4)
    86→  voiceSilenceDuration: number; // Silence before turn ends (300-800ms, default 400)
    87→  voiceBargeInEnabled: boolean; // Allow interrupting maestro (default true)
    88→  // Sync state
    89→  lastSyncedAt: Date | null;
    90→  pendingSync: boolean;
    91→  // Actions
    92→  setTheme: (theme: Theme) => void;
    93→  setProvider: (provider: AIProvider) => void;
    94→  setModel: (model: string) => void;
    95→  setBudgetLimit: (limit: number) => void;
    96→  addCost: (cost: number) => void;
    97→  updateStudentProfile: (profile: Partial<ExtendedStudentProfile>) => void;
    98→  updateAppearance: (appearance: Partial<AppearanceSettings>) => void;
    99→  setPreferredProvider: (provider: ProviderPreference) => void;
   100→  setPreferredMicrophone: (microphoneId: string) => void;
   101→  setPreferredOutput: (outputId: string) => void;
   102→  setPreferredCamera: (cameraId: string) => void;
   103→  // Voice settings actions
   104→  setVoiceVadThreshold: (threshold: number) => void;
   105→  setVoiceSilenceDuration: (duration: number) => void;
   106→  setVoiceBargeInEnabled: (enabled: boolean) => void;
   107→  // Sync actions
   108→  syncToServer: () => Promise<void>;
   109→  loadFromServer: () => Promise<void>;
   110→}
   111→
   112→export const useSettingsStore = create<SettingsState>()(
   113→  (set, get) => ({
   114→      theme: 'system',
   115→      provider: 'openai',
   116→      model: 'gpt-4o',
   117→      budgetLimit: 50,
   118→      totalSpent: 0,
   119→      studentProfile: {
   120→        name: '',
   121→        age: 14,
   122→        schoolYear: 1,
   123→        schoolLevel: 'superiore',
   124→        gradeLevel: '',
   125→        learningGoals: [],
   126→        teachingStyle: 'balanced',
   127→        fontSize: 'medium',
   128→        highContrast: false,
   129→        dyslexiaFont: false,
   130→        voiceEnabled: true,
   131→        simplifiedLanguage: false,
   132→        adhdMode: false,
   133→        // MirrorBuddy defaults
   134→        learningDifferences: [],
   135→        preferredCoach: undefined,
   136→        preferredBuddy: undefined,
   137→      },
   138→      appearance: {
   139→        theme: 'system',
   140→        accentColor: 'blue',
   141→        language: 'it',
   142→      },
   143→      preferredProvider: 'auto',
   144→      preferredMicrophoneId: '', // Empty = system default
   145→      preferredOutputId: '', // Empty = system default (speakers)
   146→      preferredCameraId: '', // Empty = system default
   147→      // Voice settings defaults
   148→      voiceVadThreshold: 0.4, // Balanced sensitivity
   149→      voiceSilenceDuration: 400, // Fast turn-taking
   150→      voiceBargeInEnabled: true, // Allow interrupting maestro
   151→      lastSyncedAt: null,
   152→      pendingSync: false,
   153→
   154→      setTheme: (theme) => set({ theme, pendingSync: true }),
   155→      setProvider: (provider) => set({ provider, pendingSync: true }),
   156→      setModel: (model) => set({ model, pendingSync: true }),
   157→      setBudgetLimit: (budgetLimit) => set({ budgetLimit, pendingSync: true }),
   158→      addCost: (cost) =>
   159→        set((state) => ({ totalSpent: state.totalSpent + cost, pendingSync: true })),
   160→      updateStudentProfile: (profile) =>
   161→        set((state) => ({
   162→          studentProfile: { ...state.studentProfile, ...profile },
   163→          pendingSync: true,
   164→        })),
   165→      updateAppearance: (appearance) =>
   166→        set((state) => ({
   167→          appearance: { ...state.appearance, ...appearance },
   168→          pendingSync: true,
   169→        })),
   170→      setPreferredProvider: (preferredProvider) =>
   171→        set({ preferredProvider, pendingSync: true }),
   172→      setPreferredMicrophone: (preferredMicrophoneId) =>
   173→        set({ preferredMicrophoneId, pendingSync: true }),
   174→      setPreferredOutput: (preferredOutputId) =>
   175→        set({ preferredOutputId, pendingSync: true }),
   176→      setPreferredCamera: (preferredCameraId) =>
   177→        set({ preferredCameraId, pendingSync: true }),
   178→      // Voice settings setters with validation
   179→      setVoiceVadThreshold: (threshold) =>
   180→        set({ voiceVadThreshold: Math.max(0.3, Math.min(0.7, threshold)), pendingSync: true }),
   181→      setVoiceSilenceDuration: (duration) =>
   182→        set({ voiceSilenceDuration: Math.max(300, Math.min(800, duration)), pendingSync: true }),
   183→      setVoiceBargeInEnabled: (enabled) =>
   184→        set({ voiceBargeInEnabled: enabled, pendingSync: true }),
   185→
   186→      syncToServer: async () => {
   187→        const state = get();
   188→        if (!state.pendingSync) return;
   189→
   190→        try {
   191→          // Sync settings
   192→          await fetch('/api/user/settings', {
   193→            method: 'PUT',
   194→            headers: { 'Content-Type': 'application/json' },
   195→            body: JSON.stringify({
   196→              theme: state.theme,
   197→              provider: state.provider,
   198→              model: state.model,
   199→              budgetLimit: state.budgetLimit,
   200→              language: state.appearance.language,
   201→              accentColor: state.appearance.accentColor,
   202→            }),
   203→          });
   204→
   205→          // Sync profile
   206→          await fetch('/api/user/profile', {
   207→            method: 'PUT',
   208→            headers: { 'Content-Type': 'application/json' },
   209→            body: JSON.stringify({
   210→              name: state.studentProfile.name,
   211→              age: state.studentProfile.age,
   212→              schoolYear: state.studentProfile.schoolYear,
   213→              schoolLevel: state.studentProfile.schoolLevel,
   214→              gradeLevel: state.studentProfile.gradeLevel,
   215→              learningGoals: state.studentProfile.learningGoals,
   216→              // Character preferences
   217→              preferredCoach: state.studentProfile.preferredCoach,
   218→              preferredBuddy: state.studentProfile.preferredBuddy,
   219→              accessibility: {
   220→                fontSize: state.studentProfile.fontSize,
   221→                highContrast: state.studentProfile.highContrast,
   222→                dyslexiaFont: state.studentProfile.dyslexiaFont,
   223→                voiceEnabled: state.studentProfile.voiceEnabled,
   224→                simplifiedLanguage: state.studentProfile.simplifiedLanguage,
   225→                adhdMode: state.studentProfile.adhdMode,
   226→              },
   227→            }),
   228→          });
   229→
   230→          set({ lastSyncedAt: new Date(), pendingSync: false });
   231→        } catch (error) {
   232→          logger.error('Settings sync failed', { error: String(error) });
   233→        }
   234→      },
   235→
   236→      loadFromServer: async () => {
   237→        try {
   238→          const [settingsRes, profileRes] = await Promise.all([
   239→            fetch('/api/user/settings'),
   240→            fetch('/api/user/profile'),
   241→          ]);
   242→
   243→          if (settingsRes.ok) {
   244→            const settings = await settingsRes.json();
   245→            set((state) => ({
   246→              theme: settings.theme ?? state.theme,
   247→              provider: settings.provider ?? state.provider,
   248→              model: settings.model ?? state.model,
   249→              budgetLimit: settings.budgetLimit ?? state.budgetLimit,
   250→              appearance: {
   251→                ...state.appearance,
   252→                language: settings.language ?? state.appearance.language,
   253→                accentColor: settings.accentColor ?? state.appearance.accentColor,
   254→              },
   255→            }));
   256→          }
   257→
   258→          if (profileRes.ok) {
   259→            const profile = await profileRes.json();
   260→            if (profile) {
   261→              const accessibility = profile.accessibility || {};
   262→              set((state) => ({
   263→                studentProfile: {
   264→                  ...state.studentProfile,
   265→                  name: profile.name ?? state.studentProfile.name,
   266→                  age: profile.age ?? state.studentProfile.age,
   267→                  schoolYear: profile.schoolYear ?? state.studentProfile.schoolYear,
   268→                  schoolLevel: profile.schoolLevel ?? state.studentProfile.schoolLevel,
   269→                  gradeLevel: profile.gradeLevel ?? state.studentProfile.gradeLevel,
   270→                  learningGoals: profile.learningGoals ?? state.studentProfile.learningGoals,
   271→                  // Character preferences
   272→                  preferredCoach: profile.preferredCoach ?? state.studentProfile.preferredCoach,
   273→                  preferredBuddy: profile.preferredBuddy ?? state.studentProfile.preferredBuddy,
   274→                  fontSize: accessibility.fontSize ?? state.studentProfile.fontSize,
   275→                  highContrast: accessibility.highContrast ?? state.studentProfile.highContrast,
   276→                  dyslexiaFont: accessibility.dyslexiaFont ?? state.studentProfile.dyslexiaFont,
   277→                  voiceEnabled: accessibility.voiceEnabled ?? state.studentProfile.voiceEnabled,
   278→                  simplifiedLanguage: accessibility.simplifiedLanguage ?? state.studentProfile.simplifiedLanguage,
   279→                  adhdMode: accessibility.adhdMode ?? state.studentProfile.adhdMode,
   280→                },
   281→              }));
   282→            }
   283→          }
   284→
   285→          set({ lastSyncedAt: new Date(), pendingSync: false });
   286→        } catch (error) {
