   293→// === PROGRESS STORE (Gamification) ===
   294→
   295→// Session grade given by maestro (1-10 scale)
   296→export interface SessionGrade {
   297→  score: number; // 1-10
   298→  feedback: string;
   299→  strengths: string[];
   300→  areasToImprove: string[];
   301→}
   302→
   303→interface StudySession {
   304→  id: string;
   305→  maestroId: string;
   306→  subject: string;
   307→  startedAt: Date;
   308→  endedAt?: Date;
   309→  durationMinutes?: number;
   310→  questionsAsked: number;
   311→  xpEarned: number;
   312→  grade?: SessionGrade; // Grade given by maestro at end of session
   313→}
   314→
   315→interface ProgressState {
   316→  xp: number;
   317→  level: number;
   318→  streak: Streak;
   319→  masteries: SubjectMastery[];
   320→  achievements: Achievement[];
   321→  totalStudyMinutes: number;
   322→  sessionsThisWeek: number;
   323→  questionsAsked: number;
   324→  // Session tracking
   325→  currentSession: StudySession | null;
   326→  sessionHistory: StudySession[];
   327→  // Sync state
   328→  lastSyncedAt: Date | null;
   329→  pendingSync: boolean;
   330→  // Actions
   331→  addXP: (amount: number) => void;
   332→  updateStreak: () => void;
   333→  updateMastery: (subjectMastery: SubjectMastery) => void;
   334→  unlockAchievement: (achievementId: string) => void;
   335→  addStudyMinutes: (minutes: number) => void;
   336→  incrementQuestions: () => void;
   337→  // Session actions
   338→  startSession: (maestroId: string, subject: string) => void;
   339→  endSession: (grade?: SessionGrade) => void;
   340→  gradeCurrentSession: (grade: SessionGrade) => void;
   341→  // Sync actions
   342→  syncToServer: () => Promise<void>;
   343→  loadFromServer: () => Promise<void>;
   344→}
   345→
   346→const XP_PER_LEVEL = [
   347→  0, 100, 250, 500, 1000, 2000, 4000, 8000, 16000, 32000, 64000,
   348→];
   349→
   350→export const useProgressStore = create<ProgressState>()(
   351→  (set, get) => ({
   352→      xp: 0,
   353→      level: 1,
   354→      streak: { current: 0, longest: 0 },
   355→      masteries: [],
   356→      achievements: [],
   357→      totalStudyMinutes: 0,
   358→      sessionsThisWeek: 0,
   359→      questionsAsked: 0,
   360→      currentSession: null,
   361→      sessionHistory: [],
   362→      lastSyncedAt: null,
   363→      pendingSync: false,
   364→
   365→      addXP: (amount) =>
   366→        set((state) => {
   367→          const newXP = state.xp + amount;
   368→          let newLevel = state.level;
   369→          while (
   370→            newLevel < XP_PER_LEVEL.length - 1 &&
   371→            newXP >= XP_PER_LEVEL[newLevel]
   372→          ) {
   373→            newLevel++;
   374→          }
   375→          // Trigger level up notification if level increased
   376→          if (newLevel > state.level) {
   377→            const levelTitles: Record<number, string> = {
   378→              1: 'Principiante',
   379→              2: 'Apprendista',
   380→              3: 'Studente',
   381→              4: 'Studioso',
   382→              5: 'Esperto',
   383→              6: 'Professore',
   384→              7: 'Gran Professore',
   385→              8: 'Saggio',
   386→              9: 'Illuminato',
   387→              10: 'Leggenda',
   388→            };
   389→            onLevelUp(newLevel, levelTitles[newLevel] || `Livello ${newLevel}`);
   390→          }
   391→          // Update current session XP
   392→          const updatedSession = state.currentSession
   393→            ? { ...state.currentSession, xpEarned: state.currentSession.xpEarned + amount }
   394→            : null;
   395→          return { xp: newXP, level: newLevel, currentSession: updatedSession, pendingSync: true };
   396→        }),
   397→
   398→      updateStreak: () =>
   399→        set((state) => {
   400→          const today = new Date().toDateString();
   401→          const lastStudy = state.streak.lastStudyDate;
   402→          const yesterday = new Date(Date.now() - 86400000).toDateString();
   403→
   404→          let newCurrent = state.streak.current;
   405→          if (!lastStudy || new Date(lastStudy).toDateString() !== today) {
   406→            if (lastStudy && new Date(lastStudy).toDateString() === yesterday) {
   407→              newCurrent++;
   408→            } else if (!lastStudy || new Date(lastStudy).toDateString() !== yesterday) {
   409→              newCurrent = 1;
   410→            }
   411→          }
   412→
   413→          // Trigger streak milestone notification if applicable
   414→          if (newCurrent > state.streak.current) {
   415→            onStreakMilestone(newCurrent);
   416→          }
   417→
   418→          return {
   419→            streak: {
   420→              current: newCurrent,
   421→              longest: Math.max(state.streak.longest, newCurrent),
   422→              lastStudyDate: new Date(),
   423→            },
   424→            pendingSync: true,
   425→          };
   426→        }),
   427→
   428→      updateMastery: (subjectMastery) =>
   429→        set((state) => {
   430→          const existing = state.masteries.findIndex(
   431→            (m) => m.subject === subjectMastery.subject
   432→          );
   433→          if (existing >= 0) {
   434→            const newMasteries = [...state.masteries];
   435→            newMasteries[existing] = subjectMastery;
   436→            return { masteries: newMasteries, pendingSync: true };
   437→          }
   438→          return { masteries: [...state.masteries, subjectMastery], pendingSync: true };
   439→        }),
   440→
   441→      unlockAchievement: (achievementId) =>
   442→        set((state) => {
   443→          const achievement = state.achievements.find(
   444→            (a) => a.id === achievementId
   445→          );
   446→          if (achievement && !achievement.unlockedAt) {
   447→            // Trigger achievement notification
   448→            onAchievement(achievement.name, achievement.description);
   449→            return {
   450→              achievements: state.achievements.map((a) =>
   451→                a.id === achievementId ? { ...a, unlockedAt: new Date() } : a
   452→              ),
   453→              pendingSync: true,
   454→            };
   455→          }
   456→          return state;
   457→        }),
   458→
   459→      addStudyMinutes: (minutes) =>
   460→        set((state) => ({
   461→          totalStudyMinutes: state.totalStudyMinutes + minutes,
   462→          pendingSync: true,
   463→        })),
   464→
   465→      incrementQuestions: () =>
   466→        set((state) => {
   467→          const updatedSession = state.currentSession
   468→            ? { ...state.currentSession, questionsAsked: state.currentSession.questionsAsked + 1 }
   469→            : null;
   470→          return {
   471→            questionsAsked: state.questionsAsked + 1,
   472→            currentSession: updatedSession,
   473→            pendingSync: true,
   474→          };
   475→        }),
   476→
   477→      startSession: (maestroId, subject) =>
   478→        set((state) => {
   479→          // End any existing session first
   480→          if (state.currentSession) {
   481→            const endedSession = {
   482→              ...state.currentSession,
   483→              endedAt: new Date(),
   484→              durationMinutes: Math.round(
   485→                (Date.now() - new Date(state.currentSession.startedAt).getTime()) / 60000
   486→              ),
   487→            };
   488→            return {
   489→              currentSession: {
   490→                id: crypto.randomUUID(),
   491→                maestroId,
   492→                subject,
   493→                startedAt: new Date(),
   494→                questionsAsked: 0,
   495→                xpEarned: 0,
   496→              },
   497→              sessionHistory: [endedSession, ...state.sessionHistory].slice(0, 100),
   498→              pendingSync: true,
   499→            };
   500→          }
   501→          return {
   502→            currentSession: {
   503→              id: crypto.randomUUID(),
   504→              maestroId,
   505→              subject,
   506→              startedAt: new Date(),
   507→              questionsAsked: 0,
   508→              xpEarned: 0,
   509→            },
   510→            pendingSync: true,
   511→          };
   512→        }),
   513→
   514→      endSession: (grade) =>
   515→        set((state) => {
   516→          if (!state.currentSession) return state;
   517→
   518→          const durationMinutes = Math.round(
   519→            (Date.now() - new Date(state.currentSession.startedAt).getTime()) / 60000
   520→          );
   521→          const endedSession = {
   522→            ...state.currentSession,
   523→            endedAt: new Date(),
   524→            durationMinutes,
   525→            grade: grade || state.currentSession.grade,
   526→          };
   527→
   528→          // Calculate week sessions
   529→          const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
   530→          const recentSessions = [endedSession, ...state.sessionHistory].filter(
   531→            (s) => new Date(s.startedAt) > weekAgo
   532→          );
   533→
   534→          return {
   535→            currentSession: null,
   536→            sessionHistory: [endedSession, ...state.sessionHistory].slice(0, 100),
   537→            totalStudyMinutes: state.totalStudyMinutes + durationMinutes,
   538→            sessionsThisWeek: recentSessions.length,
   539→            pendingSync: true,
   540→          };
   541→        }),
   542→
   543→      gradeCurrentSession: (grade) =>
   544→        set((state) => {
   545→          if (!state.currentSession) return state;
   546→          return {
   547→            currentSession: { ...state.currentSession, grade },
   548→            pendingSync: true,
   549→          };
   550→        }),
   551→
   552→      syncToServer: async () => {
   553→        const state = get();
   554→        if (!state.pendingSync) return;
   555→
   556→        try {
   557→          // Sync main progress
   558→          await fetch('/api/progress', {
   559→            method: 'PUT',
   560→            headers: { 'Content-Type': 'application/json' },
   561→            body: JSON.stringify({
   562→              xp: state.xp,
   563→              level: state.level,
   564→              streak: state.streak,
   565→              totalStudyMinutes: state.totalStudyMinutes,
   566→              questionsAsked: state.questionsAsked,
   567→              masteries: state.masteries,
   568→              achievements: state.achievements,
   569→            }),
   570→          });
   571→
   572→          // Sync recent sessions
   573→          const unsyncedSessions = state.sessionHistory.filter(
   574→            (s) => s.endedAt && !s.id.startsWith('synced-')
   575→          ).slice(0, 10);
   576→
   577→          for (const session of unsyncedSessions) {
   578→            await fetch('/api/progress/sessions', {
   579→              method: 'POST',
   580→              headers: { 'Content-Type': 'application/json' },
   581→              body: JSON.stringify(session),
   582→            });
   583→          }
   584→
   585→          set({ lastSyncedAt: new Date(), pendingSync: false });
   586→        } catch (error) {
   587→          logger.error('Progress sync failed', { error: String(error) });
   588→        }
   589→      },
   590→
   591→      loadFromServer: async () => {
   592→        try {
   593→          const [progressRes, sessionsRes] = await Promise.all([
   594→            fetch('/api/progress'),
   595→            fetch('/api/progress/sessions?limit=20'),
   596→          ]);
   597→
   598→          if (progressRes.ok) {
   599→            const data = await progressRes.json();
   600→            set((state) => ({
   601→              xp: data.xp ?? state.xp,
   602→              level: data.level ?? state.level,
   603→              streak: data.streak ?? state.streak,
   604→              masteries: data.masteries ?? state.masteries,
   605→              achievements: data.achievements ?? state.achievements,
   606→              totalStudyMinutes: data.totalStudyMinutes ?? state.totalStudyMinutes,
   607→              questionsAsked: data.questionsAsked ?? state.questionsAsked,
   608→            }));
   609→          }
   610→
   611→          if (sessionsRes.ok) {
   612→            const sessions = await sessionsRes.json();
   613→            if (Array.isArray(sessions)) {
   614→              // Calculate sessionsThisWeek from DB sessions
   615→              const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
   616→              const recentCount = sessions.filter(
   617→                (s: StudySession) => new Date(s.startedAt) > weekAgo
   618→              ).length;
   619→
   620→              set({
   621→                sessionHistory: sessions.map((s: StudySession) => ({
   622→                  ...s,
   623→                  id: `synced-${s.id}`, // Mark as synced
   624→                  startedAt: new Date(s.startedAt),
   625→                  endedAt: s.endedAt ? new Date(s.endedAt) : undefined,
   626→                })),
   627→                sessionsThisWeek: recentCount,
   628→              });
   629→            }
   630→          }
   631→
   632→          set({ lastSyncedAt: new Date(), pendingSync: false });
   633→        } catch (error) {
   634→          logger.error('Progress load failed', { error: String(error) });
   635→        }
   636→      },
   637→    })
   638→);
