   764→            body: JSON.stringify({ maestroId }),
   765→          });
   766→
   767→          if (response.ok) {
   768→            const serverConv = await response.json();
   769→            // Update with server ID
   770→            set((state) => ({
   771→              conversations: state.conversations.map((c) =>
   772→                c.id === tempId ? { ...c, id: serverConv.id } : c
   773→              ),
   774→              currentConversationId:
   775→                state.currentConversationId === tempId
   776→                  ? serverConv.id
   777→                  : state.currentConversationId,
   778→            }));
   779→            return serverConv.id;
   780→          }
   781→        } catch (error) {
   782→          logger.error('Failed to create conversation on server', { error: String(error) });
   783→        }
   784→
   785→        return tempId;
   786→      },
   787→
   788→      addMessage: async (conversationId, message) => {
   789→        const messageWithId = {
   790→          ...message,
   791→          id: crypto.randomUUID(),
   792→          timestamp: new Date(),
   793→        };
   794→
   795→        // Optimistic update
   796→        set((state) => ({
   797→          conversations: state.conversations.map((conv) =>
   798→            conv.id === conversationId
   799→              ? {
   800→                  ...conv,
   801→                  messages: [...conv.messages, messageWithId],
   802→                  updatedAt: new Date(),
   803→                  title:
   804→                    conv.messages.length === 0 && message.role === 'user'
   805→                      ? message.content.slice(0, 50)
   806→                      : conv.title,
   807→                }
   808→              : conv
   809→          ),
   810→          pendingSync: true,
   811→        }));
   812→
   813→        // Sync to server
   814→        try {
   815→          await fetch(`/api/conversations/${conversationId}/messages`, {
   816→            method: 'POST',
   817→            headers: { 'Content-Type': 'application/json' },
   818→            body: JSON.stringify({
   819→              role: message.role,
   820→              content: message.content,
   821→              toolCalls: (message as { toolCalls?: unknown }).toolCalls,
   822→            }),
   823→          });
   824→        } catch (error) {
   825→          logger.error('Failed to add message to server', { error: String(error) });
   826→        }
   827→      },
   828→
   829→      setCurrentConversation: (id) => set({ currentConversationId: id }),
   830→
   831→      deleteConversation: async (id) => {
   832→        // Optimistic update
   833→        set((state) => ({
   834→          conversations: state.conversations.filter((c) => c.id !== id),
   835→          currentConversationId:
   836→            state.currentConversationId === id
   837→              ? null
   838→              : state.currentConversationId,
   839→        }));
   840→
   841→        // Sync to server
   842→        try {
   843→          await fetch(`/api/conversations/${id}`, { method: 'DELETE' });
   844→        } catch (error) {
   845→          logger.error('Failed to delete conversation on server', { error: String(error) });
   846→        }
   847→      },
   848→
   849→      clearConversations: () =>
   850→        set({ conversations: [], currentConversationId: null }),
   851→
   852→      syncToServer: async () => {
   853→        // Conversations are synced immediately on each action
   854→        set({ lastSyncedAt: new Date(), pendingSync: false });
   855→      },
   856→
   857→      loadFromServer: async () => {
   858→        try {
   859→          const response = await fetch('/api/conversations?limit=50');
   860→          if (response.ok) {
   861→            const conversations = await response.json();
   862→            set({
   863→              conversations: conversations.map((c: {
   864→                id: string;
   865→                title: string;
   866→                maestroId: string;
   867→                createdAt: string;
   868→                updatedAt: string;
   869→                lastMessage?: string;
   870→              }) => ({
   871→                ...c,
   872→                messages: [], // Messages are loaded on-demand
   873→                createdAt: new Date(c.createdAt),
   874→                updatedAt: new Date(c.updatedAt),
   875→              })),
   876→              lastSyncedAt: new Date(),
   877→              pendingSync: false,
   878→            });
   879→          }
   880→        } catch (error) {
   881→          logger.error('Conversations load failed', { error: String(error) });
   882→        }
   883→      },
   884→    })
   885→);
   886→
   887→// === LEARNINGS STORE ===
   888→
   889→interface Learning {
   890→  id: string;
   891→  category: 'preference' | 'strength' | 'weakness' | 'interest' | 'style';
   892→  insight: string;
   893→  maestroId?: string;
   894→  subject?: string;
   895→  confidence: number;
   896→  occurrences: number;
   897→  createdAt: Date;
   898→  updatedAt: Date;
   899→}
   900→
   901→interface LearningsState {
   902→  learnings: Learning[];
   903→  lastSyncedAt: Date | null;
   904→  // Actions
   905→  addLearning: (learning: Omit<Learning, 'id' | 'occurrences' | 'createdAt' | 'updatedAt'>) => Promise<void>;
   906→  removeLearning: (id: string) => Promise<void>;
   907→  getLearningsByCategory: (category: Learning['category']) => Learning[];
   908→  // Sync
   909→  loadFromServer: () => Promise<void>;
   910→}
   911→
   912→export const useLearningsStore = create<LearningsState>()(
   913→  (set, get) => ({
   914→      learnings: [],
   915→      lastSyncedAt: null,
   916→
   917→      addLearning: async (learning) => {
   918→        try {
   919→          const response = await fetch('/api/learnings', {
   920→            method: 'POST',
   921→            headers: { 'Content-Type': 'application/json' },
   922→            body: JSON.stringify(learning),
   923→          });
   924→
   925→          if (response.ok) {
   926→            const serverLearning = await response.json();
   927→            set((state) => {
   928→              // Check if this was a reinforcement
   929→              if (serverLearning.reinforced) {
   930→                return {
   931→                  learnings: state.learnings.map((l) =>
   932→                    l.id === serverLearning.id
   933→                      ? { ...l, confidence: serverLearning.confidence, occurrences: serverLearning.occurrences }
   934→                      : l
   935→                  ),
   936→                };
   937→              }
   938→              // New learning
   939→              return {
   940→                learnings: [
   941→                  {
   942→                    ...serverLearning,
   943→                    createdAt: new Date(serverLearning.createdAt),
   944→                    updatedAt: new Date(serverLearning.updatedAt),
   945→                  },
   946→                  ...state.learnings,
   947→                ],
   948→              };
   949→            });
   950→          }
   951→        } catch (error) {
   952→          logger.error('Failed to add learning', { error: String(error) });
   953→        }
   954→      },
   955→
   956→      removeLearning: async (id) => {
