   976→            const learnings = await response.json();
   977→            set({
   978→              learnings: learnings.map((l: Learning & { createdAt: string; updatedAt: string }) => ({
   979→                ...l,
   980→                createdAt: new Date(l.createdAt),
   981→                updatedAt: new Date(l.updatedAt),
   982→              })),
   983→              lastSyncedAt: new Date(),
   984→            });
   985→          }
   986→        } catch (error) {
   987→          logger.error('Learnings load failed', { error: String(error) });
   988→        }
   989→      },
   990→    })
   991→);
   992→
   993→// === HTML SNIPPETS STORE ===
   994→
   995→export interface HTMLSnippet {
   996→  id: string;
   997→  title: string;
   998→  description?: string;
   999→  code: string; // Full HTML content (single file with embedded CSS/JS)
  1000→  subject?: string;
  1001→  maestroId?: string;
  1002→  createdAt: Date;
  1003→  updatedAt: Date;
