  1062→// === SCHOOL CALENDAR STORE ===
  1063→
  1064→export interface SchoolEvent {
  1065→  id: string;
  1066→  title: string;
  1067→  subject: string; // maps to maestro subject
  1068→  type: 'test' | 'homework' | 'project' | 'lesson' | 'exam';
  1069→  date: Date;
  1070→  description?: string;
  1071→  priority: 'low' | 'medium' | 'high';
  1072→  completed: boolean;
