  1085→  getSuggestedMaestri: () => Array<{ maestroId: string; reason: string; priority: 'high' | 'medium' | 'low' }>;
  1086→}
  1087→
  1088→// Subject to Maestro ID mapping
  1089→const SUBJECT_TO_MAESTRO: Record<string, string> = {
  1090→  mathematics: 'euclide-matematica',
  1091→  math: 'euclide-matematica',
  1092→  matematica: 'euclide-matematica',
  1093→  history: 'clio-storia',
  1094→  storia: 'clio-storia',
  1095→  italian: 'dante-italiano',
  1096→  italiano: 'dante-italiano',
  1097→  literature: 'dante-italiano',
  1098→  letteratura: 'dante-italiano',
  1099→  english: 'shakespeare-english',
  1100→  inglese: 'shakespeare-english',
  1101→  science: 'curie-scienze',
  1102→  scienze: 'curie-scienze',
  1103→  physics: 'einstein-fisica',
  1104→  fisica: 'einstein-fisica',
  1105→  chemistry: 'curie-scienze',
  1106→  chimica: 'curie-scienze',
  1107→  biology: 'darwin-biologia',
  1108→  biologia: 'darwin-biologia',
  1109→  art: 'leonardo-arte',
  1110→  arte: 'leonardo-arte',
  1111→  philosophy: 'socrate-filosofia',
  1112→  filosofia: 'socrate-filosofia',
  1113→  geography: 'colombo-geografia',
  1114→  geografia: 'colombo-geografia',
  1115→  music: 'mozart-musica',
  1116→  musica: 'mozart-musica',
  1117→  latin: 'cicerone-latino',
  1118→  latino: 'cicerone-latino',
  1119→  greek: 'aristotele-greco',
  1120→  greco: 'aristotele-greco',
  1121→};
  1122→
  1123→export const useCalendarStore = create<CalendarState>()(
  1124→  (set, get) => ({
  1125→      events: [],
  1126→
  1127→      addEvent: (event) =>
  1128→        set((state) => {
  1129→          const subjectLower = event.subject.toLowerCase();
  1130→          const maestroId = SUBJECT_TO_MAESTRO[subjectLower];
  1131→          return {
  1132→            events: [
  1133→              ...state.events,
  1134→              {
  1135→                ...event,
  1136→                id: crypto.randomUUID(),
  1137→                completed: false,
  1138→                maestroSuggested: maestroId,
  1139→              },
  1140→            ],
  1141→          };
  1142→        }),
  1143→
  1144→      updateEvent: (id, updates) =>
  1145→        set((state) => ({
  1146→          events: state.events.map((e) =>
  1147→            e.id === id ? { ...e, ...updates } : e
  1148→          ),
  1149→        })),
  1150→
  1151→      deleteEvent: (id) =>
  1152→        set((state) => ({
  1153→          events: state.events.filter((e) => e.id !== id),
  1154→        })),
  1155→
  1156→      toggleCompleted: (id) =>
  1157→        set((state) => ({
  1158→          events: state.events.map((e) =>
  1159→            e.id === id ? { ...e, completed: !e.completed } : e
  1160→          ),
  1161→        })),
  1162→
  1163→      getUpcomingEvents: (days) => {
  1164→        const now = new Date();
  1165→        const future = new Date(now.getTime() + days * 24 * 60 * 60 * 1000);
  1166→        return get()
  1167→          .events.filter(
  1168→            (e) => !e.completed && new Date(e.date) >= now && new Date(e.date) <= future
  1169→          )
  1170→          .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  1171→      },
  1172→
  1173→      getEventsBySubject: (subject) => {
  1174→        return get().events.filter(
  1175→          (e) => e.subject.toLowerCase() === subject.toLowerCase()
  1176→        );
  1177→      },
  1178→
  1179→      getSuggestedMaestri: () => {
  1180→        const upcoming = get().getUpcomingEvents(7);
  1181→        const suggestions: Map<string, { count: number; nearestDays: number; types: Set<string> }> = new Map();
  1182→
  1183→        const now = new Date();
  1184→        upcoming.forEach((event) => {
  1185→          const maestroId = event.maestroSuggested;
  1186→          if (!maestroId) return;
  1187→
  1188→          const daysUntil = Math.ceil(
  1189→            (new Date(event.date).getTime() - now.getTime()) / (24 * 60 * 60 * 1000)
  1190→          );
  1191→
  1192→          if (suggestions.has(maestroId)) {
  1193→            const existing = suggestions.get(maestroId)!;
  1194→            existing.count++;
  1195→            existing.nearestDays = Math.min(existing.nearestDays, daysUntil);
  1196→            existing.types.add(event.type);
  1197→          } else {
  1198→            suggestions.set(maestroId, {
  1199→              count: 1,
  1200→              nearestDays: daysUntil,
  1201→              types: new Set([event.type]),
  1202→            });
  1203→          }
  1204→        });
  1205→
  1206→        return Array.from(suggestions.entries())
  1207→          .map(([maestroId, data]) => {
  1208→            let priority: 'high' | 'medium' | 'low' = 'low';
  1209→            let reason = '';
  1210→
  1211→            if (data.nearestDays <= 1) {
  1212→              priority = 'high';
  1213→              reason = data.types.has('exam') || data.types.has('test')
  1214→                ? 'Test tomorrow - review now!'
  1215→                : 'Event tomorrow';
  1216→            } else if (data.nearestDays <= 3) {
  1217→              priority = 'high';
  1218→              reason = `${data.count} event${data.count > 1 ? 's' : ''} in ${data.nearestDays} days`;
  1219→            } else if (data.nearestDays <= 5) {
  1220→              priority = 'medium';
  1221→              reason = `Prepare for upcoming ${Array.from(data.types).join('/')}`;
  1222→            } else {
  1223→              priority = 'low';
  1224→              reason = `${data.count} event${data.count > 1 ? 's' : ''} this week`;
  1225→            }
  1226→
  1227→            return { maestroId, reason, priority };
  1228→          })
  1229→          .sort((a, b) => {
  1230→            const priorityOrder = { high: 0, medium: 1, low: 2 };
  1231→            return priorityOrder[a.priority] - priorityOrder[b.priority];
  1232→          });
  1233→      },
  1234→    })
  1235→);
  1236→
  1237→// === UI STORE ===
  1238→
  1239→interface UIState {
  1240→  sidebarOpen: boolean;
  1241→  settingsOpen: boolean;
  1242→  currentView: 'maestri' | 'chat' | 'voice' | 'quiz' | 'flashcards' | 'homework' | 'progress';
  1243→  // Actions
  1244→  toggleSidebar: () => void;
  1245→  setSidebarOpen: (open: boolean) => void;
  1246→  toggleSettings: () => void;
  1247→  setCurrentView: (view: UIState['currentView']) => void;
  1248→}
  1249→
  1250→export const useUIStore = create<UIState>((set) => ({
  1251→  sidebarOpen: true,
  1252→  settingsOpen: false,
  1253→  currentView: 'maestri',
  1254→  toggleSidebar: () => set((state) => ({ sidebarOpen: !state.sidebarOpen })),
  1255→  setSidebarOpen: (sidebarOpen) => set({ sidebarOpen }),
  1256→  toggleSettings: () => set((state) => ({ settingsOpen: !state.settingsOpen })),
  1257→  setCurrentView: (currentView) => set({ currentView }),
  1258→}));
  1259→
  1260→// === SYNC HOOK ===
  1261→
  1262→export async function initializeStores() {
  1263→  // Ensure user exists (creates cookie if needed)
  1264→  await fetch('/api/user');
  1265→
  1266→  // Load data from server
  1267→  await Promise.all([
  1268→    useSettingsStore.getState().loadFromServer(),
  1269→    useProgressStore.getState().loadFromServer(),
  1270→    useConversationStore.getState().loadFromServer(),
  1271→    useLearningsStore.getState().loadFromServer(),
  1272→  ]);
  1273→}
  1274→
  1275→export function setupAutoSync(intervalMs = 30000) {
  1276→  // Auto-sync every 30 seconds if there are pending changes
  1277→  return setInterval(async () => {
  1278→    const settings = useSettingsStore.getState();
  1279→    const progress = useProgressStore.getState();
  1280→
  1281→    if (settings.pendingSync) {
  1282→      await settings.syncToServer();
  1283→    }
  1284→    if (progress.pendingSync) {
  1285→      await progress.syncToServer();
  1286→    }
  1287→  }, intervalMs);
  1288→}
