    95→
    96→  // Save student summary to materials archive
    97→  const handleSaveStudentSummary = useCallback(async (data: StudentSummaryData) => {
    98→    try {
    99→      const userId = getUserId();
   100→      const response = await fetch('/api/tools/saved', {
   101→        method: 'POST',
   102→        headers: { 'Content-Type': 'application/json' },
   103→        body: JSON.stringify({
   104→          userId,
