   107→          topic: data.topic,
   108→          content: data,
   109→          maestroId: data.maestroId,
   110→          sessionId: data.sessionId,
   111→        }),
   112→      });
   113→      if (!response.ok) {
   114→        throw new Error(`Save failed: ${response.status}`);
   115→      }
   116→      logger.info('Student summary saved', { title: data.title });
   117→    } catch (error) {
   118→      logger.error('Failed to save student summary', { error: String(error) });
   119→      throw error;
   120→    }
   121→  }, []);
   122→
   123→  const {
   124→    connectionState,
   125→    activeTool,
   126→    eventsReceived,
   127→  } = useToolStream({
   128→    sessionId,
   129→    autoConnect: true,
   130→    onEvent: (event) => {
   131→      if (event.type === 'tool:complete' && activeTool) {
   132→        onToolComplete?.(activeTool);
