   148→          bg: 'bg-blue-900/20',
   149→        };
   150→      case 'completed':
   151→        return {
   152→          icon: <CheckCircle className="w-4 h-4" />,
   153→          text: 'Completato!',
   154→          color: 'text-green-400',
   155→          bg: 'bg-green-900/20',
   156→        };
   157→      case 'error':
   158→        return {
   159→          icon: <XCircle className="w-4 h-4" />,
   160→          text: 'Errore',
   161→          color: 'text-red-400',
   162→          bg: 'bg-red-900/20',
   163→        };
   164→      case 'cancelled':
   165→        return {
   166→          icon: <Pause className="w-4 h-4" />,
   167→          text: 'Annullato',
   168→          color: 'text-yellow-400',
   169→          bg: 'bg-yellow-900/20',
   170→        };
