   177→        'relative w-full h-full min-h-[400px] bg-slate-900 rounded-2xl overflow-hidden',
   178→        isFullscreen && 'fixed inset-0 z-50 rounded-none',
   179→        className
   180→      )}
   181→      role="region"
   182→      aria-label="Tool Canvas"
   183→    >
   184→      {/* Connection status overlay */}
   185→      <AnimatePresence>
   186→        {connectionState !== 'connected' && (
   187→          <motion.div
   188→            initial={{ opacity: 0 }}
