   199→              )}
   200→              {connectionState === 'reconnecting' && (
   201→                <>
   202→                  <Loader2 className="w-8 h-8 animate-spin text-yellow-500 mx-auto" />
   203→                  <p className="text-slate-400">Riconnessione...</p>
   204→                </>
   205→              )}
   206→              {connectionState === 'error' && (
   207→                <>
   208→                  <XCircle className="w-8 h-8 text-red-500 mx-auto" />
