   218→            </div>
   219→          </motion.div>
   220→        )}
   221→      </AnimatePresence>
   222→
   223→      {/* Main canvas area (80%) */}
   224→      <div className="absolute inset-0 pr-0 md:pr-[20%]">
   225→        <AnimatePresence mode="wait">
   226→          {!activeTool && connectionState === 'connected' && (
   227→            <motion.div
   228→              key="waiting"
