   287→                    onClick={() => setIsFullscreen(!isFullscreen)}
   288→                    className="p-2 rounded-lg hover:bg-slate-800 transition-colors"
   289→                    aria-label={isFullscreen ? 'Esci da fullscreen' : 'Fullscreen'}
   290→                  >
   291→                    {isFullscreen ? (
   292→                      <Minimize2 className="w-5 h-5 text-slate-400" />
   293→                    ) : (
   294→                      <Maximize2 className="w-5 h-5 text-slate-400" />
   295→                    )}
   296→                  </button>
   297→
   298→                  {onCancel && activeTool.status === 'building' && (
   299→                    <button
   300→                      onClick={onCancel}
   301→                      className="p-2 rounded-lg hover:bg-red-900/50 transition-colors"
   302→                      aria-label="Annulla"
   303→                    >
   304→                      <X className="w-5 h-5 text-red-400" />
   305→                    </button>
   306→                  )}
   307→                </div>
   308→              </div>
   309→
   310→              {/* Progress bar */}
