   315→              )}
   316→
   317→              {/* Tool content */}
   318→              <div className="flex-1 overflow-auto p-4">
   319→                <ToolRenderer tool={activeTool} onSaveStudentSummary={handleSaveStudentSummary} />
   320→              </div>
   321→            </motion.div>
   322→          )}
   323→        </AnimatePresence>
   324→      </div>
   325→
   326→      {/* Maestro PiP (20%) - Right side */}
   327→      <AnimatePresence>
   328→        {showPiP && (
   329→          <motion.div
   330→            initial={{ x: 100, opacity: 0 }}
   331→            animate={{ x: 0, opacity: 1 }}
   332→            exit={{ x: 100, opacity: 0 }}
   333→            className="hidden md:block absolute top-0 right-0 w-[20%] h-full border-l border-slate-800 bg-slate-900/95"
   334→          >
   335→            {/* PiP Header */}
   336→            <div className="p-4 border-b border-slate-800">
   337→              <div className="flex items-center gap-3">
   338→                {maestroAvatar ? (
   339→                  <Image
   340→                    src={maestroAvatar}
   341→                    alt={maestroName}
   342→                    width={48}
   343→                    height={48}
   344→                    className="w-12 h-12 rounded-full object-cover"
   345→                  />
   346→                ) : (
   347→                  <div className="w-12 h-12 rounded-full bg-gradient-to-br from-purple-500 to-pink-600 flex items-center justify-center text-white font-bold">
   348→                    {maestroName.charAt(0)}
   349→                  </div>
   350→                )}
   351→                <div>
   352→                  <p className="font-medium text-white">{maestroName}</p>
   353→                  <p className="text-xs text-slate-400">Sta costruendo...</p>
   354→                </div>
   355→              </div>
   356→            </div>
   357→
   358→            {/* Building animation */}
   359→            <div className="p-4">
   360→              <div className="aspect-square rounded-xl bg-slate-800 flex items-center justify-center overflow-hidden">
   361→                {activeTool?.status === 'building' && (
   362→                  <BuildingAnimation toolType={activeTool.type} />
   363→                )}
   364→                {(!activeTool || activeTool.status === 'completed') && (
   365→                  <div className="text-center p-4">
   366→                    <p className="text-sm text-slate-500">
   367→                      {activeTool
   368→                        ? 'Strumento completato!'
   369→                        : 'In attesa...'}
   370→                    </p>
   371→                  </div>
   372→                )}
   373→              </div>
   374→            </div>
   375→
   376→            {/* Stats */}
   377→            <div className="p-4 border-t border-slate-800">
   378→              <div className="text-xs text-slate-500 space-y-1">
   379→                <p>Eventi ricevuti: {eventsReceived}</p>
   380→                {activeTool && (
   381→                  <p>Chunks: {activeTool.chunks.length}</p>
   382→                )}
   383→              </div>
   384→            </div>
   385→
   386→            {/* Hide PiP button */}
   387→            <button
   388→              onClick={() => setShowPiP(false)}
   389→              className="absolute top-2 right-2 p-1 rounded hover:bg-slate-800 transition-colors"
   390→              aria-label="Nascondi PiP"
   391→            >
   392→              <X className="w-4 h-4 text-slate-500" />
   393→            </button>
   394→          </motion.div>
   395→        )}
   396→      </AnimatePresence>
   397→
   398→      {/* Show PiP button when hidden */}
   399→      {!showPiP && (
   400→        <button
   401→          onClick={() => setShowPiP(true)}
   402→          className="hidden md:flex absolute bottom-4 right-4 items-center gap-2 px-3 py-2 rounded-lg bg-slate-800 hover:bg-slate-700 transition-colors text-sm text-slate-300"
   403→        >
   404→          Mostra {maestroName}
   405→        </button>
   406→      )}
   407→    </div>
   408→  );
   409→}
   410→
   411→// Tool-specific renderer
   412→function ToolRenderer({ tool, onSaveStudentSummary }: { tool: ActiveToolState; onSaveStudentSummary?: (data: StudentSummaryData) => Promise<void> }) {
   413→  // Handle incomplete content during building
   414→  if (tool.status === 'building' && !tool.content) {
   415→    return (
   416→      <div className="h-full flex items-center justify-center">
   417→        <div className="text-center space-y-4">
   418→          <Loader2 className="w-8 h-8 animate-spin text-blue-500 mx-auto" />
   419→          <p className="text-slate-400">Preparazione in corso...</p>
   420→          {tool.chunks.length > 0 && (
   421→            <p className="text-xs text-slate-500">
   422→              Ricevuti {tool.chunks.length} frammenti
   423→            </p>
   424→          )}
   425→        </div>
   426→      </div>
   427→    );
   428→  }
   429→
   430→  // Error state
   431→  if (tool.status === 'error') {
   432→    return (
   433→      <div className="h-full flex items-center justify-center">
   434→        <div className="text-center space-y-4 p-8 bg-red-900/20 rounded-xl">
   435→          <XCircle className="w-12 h-12 text-red-400 mx-auto" />
   436→          <p className="text-red-400">{tool.errorMessage || 'Si è verificato un errore'}</p>
   437→        </div>
   438→      </div>
   439→    );
   440→  }
   441→
   442→  // Cancelled state
   443→  if (tool.status === 'cancelled') {
   444→    return (
   445→      <div className="h-full flex items-center justify-center">
   446→        <div className="text-center space-y-4 p-8 bg-yellow-900/20 rounded-xl">
   447→          <Pause className="w-12 h-12 text-yellow-400 mx-auto" />
   448→          <p className="text-yellow-400">Costruzione annullata</p>
   449→        </div>
   450→      </div>
   451→    );
   452→  }
   453→
   454→  // Render based on tool type
   455→  switch (tool.type) {
   456→    case 'mindmap':
   457→      return (
   458→        <MindmapRenderer
   459→          title={(tool.content as MindmapRequest)?.title || tool.title}
   460→          nodes={(tool.content as MindmapRequest)?.nodes || []}
   461→        />
   462→      );
   463→
   464→    case 'quiz':
   465→      return (
   466→        <QuizTool
   467→          request={tool.content as QuizRequest}
   468→        />
   469→      );
   470→
   471→    case 'flashcards':
   472→      return (
   473→        <FlashcardTool
